import java.io.IOException;
import javax.servlet.http.*;

public class SecureServlet extends HttpServlet {
    protected void doGet(HttpServletRequest request, HttpServletResponse response) throws IOException {
        String userInput = request.getParameter("input");
        String sanitizedInput = sanitizeInput(userInput);
        String output = "Hello, " + sanitizedInput + "!";

        response.setContentType("text/html");
        response.getWriter().write(output);
    }

    private String sanitizeInput(String input) {
        // Perform proper input sanitization here (e.g., using OWASP ESAPI library)
        // For demonstration purposes, we will simply HTML encode the input
        return htmlEncode(input);
    }

    private String htmlEncode(String input) {
        return input
                .replace("&", "&amp;")
                .replace("<", "&lt;")
                .replace(">", "&gt;")
                .replace("\"", "&quot;")
                .replace("'", "&#39;");
    }
}

### Explanation:
취약유형: Cross-Site Scripting (XSS)
